  1708→  private SymAST[] parseExps(Token separator, Token delim) {
  1709→    /* Parses '<exp-list> <delim>' where 
  1710→         <exp-list>      ::= <empty> | <prop-exp-list>
  1711→         <empty> ::=  
  1712→         <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list>
  1713→     */
  1714→    
  1715→    LinkedList<SymAST> exps = new LinkedList<SymAST>();
  1716→    Token next = in.peek();
  1717→    
  1718→    if (next == delim) {
  1719→      in.readToken(); // consume RightParen
  1720→      return new SymAST[0];
  1721→    }
  1722→    
  1723→    /* next is still at front of input stream */
  1724→    
  1725→    do {
  1726→      SymAST exp = parseExp();
  1727→      exps.addLast(exp);
  1728→      next = in.readToken();
  1729→    } while (next == separator);
  1730→    
  1731→    if (next != delim) error(next,"`,' or `)'");
  1732→    return exps.toArray(new SymAST[0]);
  1733→  }
