  1737→  private Variable[] parseVars() {
  1738→    
  1739→    /* Parses <id-list> where
  1740→     * <id-list>       ::= <empty> | <prop-id-list>
  1741→     * <prop-id-list>  ::= <id> | <id> , <id-list> 
  1742→     
  1743→     * NOTE: consumes `to' following <id-list> */
  1744→    
  1745→    LinkedList<Variable> vars = new LinkedList<Variable>();
  1746→    Token t = in.readToken();
  1747→    if (t == toKey) return new Variable[0];
  1748→    
  1749→    do {
  1750→      if (! (t instanceof Variable)) error(t,"variable");
  1751→      vars.addLast((Variable)t);
  1752→      t = in.readToken();
  1753→      if (t == toKey) break; 
  1754→      if (t != Comma.ONLY) error(t,"`to' or `,'");
  1755→      /* Comma found, read next variable */
  1756→      t = in.readToken();
  1757→    } while (true);
  1758→    return (Variable[]) vars.toArray(new Variable[0]);
  1759→  }
