  1761→  private Def[] parseDefs(boolean forceMap) {
  1762→    /* Parses  `<prop-def-list> in' where
  1763→        <prop-def-list> ::= <def> | <def> <def-list> 
  1764→    
  1765→       NOTE: consumes `in' following <prop-def-list>
  1766→     */
  1767→    
  1768→    LinkedList<Def> defs = new LinkedList<Def>();
  1769→    Token t = in.readToken();
  1770→    
  1771→    do {
  1772→      Def d = parseDef(t);        
  1773→      if (forceMap && (! (d.rhs() instanceof Map)))
  1774→        throw new ParseException("right hand side of definition `" + d
  1775→                                   + "' is not a map expression");
  1776→      defs.addLast(d);
  1777→      t = in.readToken();
  1778→    } while (t != inKey);
  1779→    
  1780→    return (Def[]) defs.toArray(new Def[0]);
  1781→  }
