  1783→  private Def parseDef(Token var) {
  1784→    /* Parses <id> := <exp> ;
  1785→     * which is <def> given that first token var has been read.
  1786→     */
  1787→    
  1788→    if (! (var instanceof Variable)) error(var,"variable");
  1789→    
  1790→    Token bind = in.readToken();
  1791→    if (bind != Bind.ONLY) error (bind,"`:='");
  1792→    
  1793→    SymAST exp = parseExp();
  1794→    
  1795→    Token semi = in.readToken();
  1796→    if (semi != SemiColon.ONLY) error(semi,"`;'");
  1797→    return new Def((Variable) var, exp);
  1798→  }
