/*  EvalVisitor methods for evaluating SDASTs. */
public SDASTVisitor<JamVal> newEvalVisitor(SDEnv env) { return new SDEvaluator(env); }

/** Looks up the value of a static-distance variable in the environment. */
public JamVal forSDPair(SDPair p) { return env.lookup(p); }

/** Creates a closure for a static-distance map. */
public JamVal forSMap(SMap sm) { return new SDClosure(sm, this); }

/** Evaluates rhss in current env, extends env with results, then evaluates body. */
public JamVal forSLet(SLet sl) {
  SDAST[] rhss = sl.rhss();
  int n = rhss.length;
  JamVal[] vals = new JamVal[n];
  for (int i = 0; i < n; i++)
    vals[i] = rhss[i].accept(this);
  SDEnv newEnv = env.cons(vals);
  return sl.body().accept(new SDEvaluator(newEnv));
}

/** Creates new env frame (pre-allocated), evaluates recursive rhss, then evaluates body. */
public JamVal forSLetRec(SLetRec slr) {
  SDAST[] rhss = slr.rhss();
  int n = rhss.length;
  JamVal[] vals = new JamVal[n];  // mutable array shared with newEnv
  SDEnv newEnv = env.cons(vals);
  SDEvaluator newEvaluator = new SDEvaluator(newEnv);
  for (int i = 0; i < n; i++)
    vals[i] = rhss[i].accept(newEvaluator);  // fills in the shared array
  return slr.body().accept(newEvaluator);
}

